// MARK: - AppDeepLink
enum AppDeepLink {
    case profile(id: String)
    case paymentConfirmation
    case adminSettings
    case unknown

    init(url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            self = .unknown
            return
        }

        let pathComponents = components.path.split(separator: "/").map(String.init)

        if pathComponents.count >= 2 {
            switch pathComponents[0] {
            case "profile":
                if let profileID = pathComponents[1] as String? {
                    self = .profile(id: profileID)
                    return
                }
            case "payment":
                if pathComponents[1] == "confirm" {
                    self = .paymentConfirmation
                    return
                }
            case "admin":
                if pathComponents[1] == "settings" {
                    self = .adminSettings
                    return
                }
            default:
                break
            }
        }
        self = .unknown
    }
}

// MARK: - DeepLinkRouter
class DeepLinkRouter {

    static let shared = DeepLinkRouter()

    private init() {}

    private var window: UIWindow? {
        if #available(iOS 13.0, *) {
            return UIApplication.shared.connectedScenes
                .filter { $0.activationState == .foregroundActive }
                .first(where: { $0 is UIWindowScene })
                .flatMap({ $0 as? UIWindowScene })?.windows
                .first(where: { $0.isKeyWindow })
        } else {
            return UIApplication.shared.keyWindow
        }
    }

    private var rootNavigationController: UINavigationController? {
        return window?.rootViewController as? UINavigationController
    }

    func handleDeepLink(_ deepLink: AppDeepLink) {
        guard let navigationController = rootNavigationController else {
            print("Error: Root navigation controller not found.")
            return
        }

        // Pop to root to clear previous stack before navigating to new deep link destination
        // Or implement a more sophisticated stack management if required
        navigationController.popToRootViewController(animated: false)

        switch deepLink {
        case .profile(let id):
            navigateToProfile(profileID: id, navigationController: navigationController)
        case .paymentConfirmation:
            navigateToPaymentConfirmation(navigationController: navigationController)
        case .adminSettings:
            navigateToAdminSettings(navigationController: navigationController)
        case .unknown:
            showUnknownLinkAlert(navigationController: navigationController)
        }
    }

    private func navigateToProfile(profileID: String, navigationController: UINavigationController) {
        let profileVC = ProfileViewController() // Assume ProfileViewController exists
        profileVC.profileID = profileID
        navigationController.pushViewController(profileVC, animated: true)
        print("Navigated to Profile for ID: \(profileID)")
    }

    private func navigateToPaymentConfirmation(navigationController: UINavigationController) {
        let paymentVC = PaymentConfirmationViewController() // Assume PaymentConfirmationViewController exists
        navigationController.pushViewController(paymentVC, animated: true)
        print("Navigated to Payment Confirmation")
    }

    private func navigateToAdminSettings(navigationController: UINavigationController) {
        let adminVC = AdminSettingsViewController() // Assume AdminSettingsViewController exists
        navigationController.pushViewController(adminVC, animated: true)
        print("Navigated to Admin Settings")
    }

    private func showUnknownLinkAlert(navigationController: UINavigationController) {
        let alert = UIAlertController(title: "Invalid Link", message: "The link you followed is not recognized.", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default, handler: nil))
        navigationController.present(alert, animated: true, completion: nil)
        print("Handled unknown deep link.")
    }
}

